function Login() {
  return (
    <div className="page-center">
      <div className="auth-card">
        <h2>Login</h2>

        <input placeholder="Email" />
        <input type="password" placeholder="Password" />

        <button className="btn">Login</button>

        <a href="/register">New user? Register</a>
      </div>
    </div>
  );
}

export default Login;
